// src/generator/utils/worker/encoding.ts

export function escapeXml(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
}

export function rleEncode(arr: Uint8Array): string {
  const parts: string[] = [];
  let i = 0;
  while (i < arr.length) {
    const v = arr[i];
    let count = 1;
    while (i + count < arr.length && arr[i + count] === v && count < 255) count++;
    parts.push(String.fromCharCode(v, count));
    i += count;
  }
  return btoa(parts.join(""));
}