// src/generator/utils/image.worker.ts
import type { RGB, PaintProfile } from '../../config';
import { rgbToLab, rgbToHsl, hslToRgb, deltaE00, labToRgb } from '../../utils/colorMath';
import { applyArtisticStrategy, multiLevelNotan, customPaletteStrategy, blendWithIntensity } from '../../utils/colorStrategies';
import type { ArtisticPresetId } from '../../config';
import { generateSvgTemplate, generateArtisticHtmlTemplate, generatePbnHtmlTemplate } from './exportTemplates';

// Импортируем наши новые модули
import { medianCut } from './worker/quantization';
import { bilateralFilter, fastRegionCleanup, modeFilter, thickeningFilter } from './worker/filters';
import { extractBoundaryEdges, marchingSquaresContour } from './worker/contours';
import { distTransform, generateLabelPositions, resolveAllLabelCollisions } from './worker/labels';
import { escapeXml, rleEncode } from './worker/encoding';
import { buildSmoothChains, simplifyDP, smoothPathSmart } from './worker/geometry';

export interface SolverCandidate {
  drops: number[];
  delta: number;
  total: number;
  used: number;
}

export interface WorkerEventData {
  target: [number, number, number];
  crgb: [number, number, number][];
  n: number;
  mpc: number;
  isF: boolean;
  tt: number | null;
  tLab: [number, number, number];
  profile: PaintProfile;
  subColor: [number, number, number];
  maxMix: number;
}

function computeArtisticColor(
  rgbArr: [number, number, number],
  artisticStep: number,
  preset: string,
  notanLevels: number,
  notanThreshold: number,
  artIntensity: number,
  customArtPalette?: [number, number, number][],
): [number, number, number] {
  if (artisticStep === 1) { // Тень
    return multiLevelNotan(rgbArr, notanLevels, notanThreshold);
  } else if (artisticStep === 2) { // Цвета
    if (preset === 'original') return rgbArr;
    if (customArtPalette && customArtPalette.length >= 2) {
      const styled = customPaletteStrategy(rgbArr, customArtPalette);
      if (artIntensity < 100) {
        return blendWithIntensity(rgbArr, styled, artIntensity);
      }
      return styled;
    }
    return applyArtisticStrategy(rgbArr, preset as any, artIntensity);
  } else {
    // Шаг 0 (Контуры) и 3 (Детали)
    return rgbArr;
  }
}

// ─── ОБРАБОТЧИК СООБЩЕНИЙ ВОРКЕРА ───
self.onmessage = function (e: MessageEvent) {
  const { type } = e.data;

  // 1. ГЕНЕРАЦИЯ СХЕМЫ ИЗ ИЗОБРАЖЕНИЯ
  if (type === "process") {
    const { imgBuffer, width: W, height: H, numColors, detail } = e.data.payload;
    const data = new Uint8ClampedArray(imgBuffer);
    const N = W * H;

    const postProgress = (msg: string, pct: number) => {
      self.postMessage({ type: "progress", msg, pct });
    };

    try {
      postProgress("Подбор палитры…", 5);
      const palette = medianCut(data, W, H, Math.max(2, Math.min(numColors, 250)));
      const K = palette.length;
      const palLab = palette.map((c) => rgbToLab(c));

      postProgress("Подготовка (Сглаживание)…", 10);
      // Для красивых, плавных векторных линий нам нужно сгладить исходный шум (шерсть, зерно матрицы).
      // Даже на максимальной детализации радиус не должен падать до 0, иначе мы получим пиксельный мусор.
      const radius = detail >= 9 ? 1 : detail >= 7 ? 2 : detail >= 4 ? 3 : 4;
      const sm = bilateralFilter(data, W, H, radius);

      postProgress("Присвоение цветов…", 20);
      const mask = new Uint8Array(N);
      for (let i = 0; i < N; i++) {
        const p = i * 4;
        const lab = rgbToLab([sm[p], sm[p + 1], sm[p + 2]]);
        let bd = Infinity, bk = 0;
        for (let c = 0; c < K; c++) {
          const dL = lab[0] - palLab[c][0], da = lab[1] - palLab[c][1], db = lab[2] - palLab[c][2];
          const d = dL * dL + da * da * 1.1 + db * db * 1.1;
          if (d < bd) { bd = d; bk = c; }
        }
        mask[i] = bk;
      }

      const baseArea = N / 500000;
      // Даже на 10 детализации минимальная зона должна быть хотя бы 6-8 пикселей,
      // иначе она физически не прокрасится и будет выглядеть как грязь/ступенька.
      const computedMinArea = Math.max(8, Math.round(baseArea * (12 - detail) * (12 - detail)));

      postProgress("Быстрое объединение мелких зон…", 30);
      const cleaned = fastRegionCleanup(mask, W, H, computedMinArea, palLab);

      postProgress("Фильтрация шума…", 50);
      let final = cleaned;
      // Модальный фильтр делает края "ступенчатыми" (axis-aligned).
      // Делаем минимум 2 прохода, чтобы убить одиночные пиксели-выступы (سبب ступенек).
      const modePasses = detail <= 4 ? 4 : detail <= 7 ? 3 : 2;
      for (let pass = 0; pass < modePasses; pass++) {
        final = modeFilter(final, W, H, K);
      }

      postProgress("Устранение узких зон…", 55);
      // Узкие зоны (в 1 пиксель) при сглаживании контуров "съедаются" или выворачиваются наизнанку.
      // Поэтому мы принудительно утолщаем их или удаляем.
      const minThickness = detail <= 4 ? 3.0 : detail <= 7 ? 2.4 : 2.0;
      final = thickeningFilter(final, W, H, minThickness);

      postProgress("Финальная очистка мелких артефактов…", 58);
      // После фильтров могли образоваться новые микро-зоны. Уничтожаем их, чтобы не было "белых пятен".
      final = fastRegionCleanup(final, W, H, computedMinArea, palLab);

      postProgress("Построение границ…", 59);
      const boundaryEdges = extractBoundaryEdges(final, W, H);

      const edgeDegree = new Map<string, number>();
      for (let i = 0; i < boundaryEdges.length; i++) {
        const edge = boundaryEdges[i];
        const k1 = `${edge[0]},${edge[1]}`;
        const k2 = `${edge[2]},${edge[3]}`;
        edgeDegree.set(k1, (edgeDegree.get(k1) || 0) + 1);
        edgeDegree.set(k2, (edgeDegree.get(k2) || 0) + 1);
      }
      const junctions = new Set<string>();
      for (const [k, deg] of edgeDegree) {
        if (deg !== 2) junctions.add(k);
      }
      junctions.add(`0,0`);
      junctions.add(`${W},0`);
      junctions.add(`0,${H}`);
      junctions.add(`${W},${H}`);

      postProgress("Трассировка контуров…", 60);
      const contours: any[] = [];
      const valid = new Set<number>();

      // Гарантируем, что все цвета, оставшиеся на холсте, попадут в палитру (защита от белых дыр)
      for (let i = 0; i < N; i++) {
        valid.add(final[i]);
      }

      const extractContoursForColor = (ci: number) => {
        const labels = new Int32Array(N).fill(-1);
        const q = new Int32Array(N);
        let count = 0;

        for (let i = 0; i < N; i++) {
          if (final[i] === ci && labels[i] === -1) {
            let head = 0, tail = 0;
            q[tail++] = i;
            labels[i] = count;
            let area = 0;
            let minX = W, minY = H, maxX = -1, maxY = -1;

            while (head < tail) {
              const curr = q[head++];
              area++;
              const cx = curr % W;
              const cy = Math.floor(curr / W);

              if (cx < minX) minX = cx;
              if (cx > maxX) maxX = cx;
              if (cy < minY) minY = cy;
              if (cy > maxY) maxY = cy;

              if (cx > 0 && final[curr - 1] === ci && labels[curr - 1] === -1) { labels[curr - 1] = count; q[tail++] = curr - 1; }
              if (cx < W - 1 && final[curr + 1] === ci && labels[curr + 1] === -1) { labels[curr + 1] = count; q[tail++] = curr + 1; }
              if (cy > 0 && final[curr - W] === ci && labels[curr - W] === -1) { labels[curr - W] = count; q[tail++] = curr - W; }
              if (cy < H - 1 && final[curr + W] === ci && labels[curr + W] === -1) { labels[curr + W] = count; q[tail++] = curr + W; }
            }

            if (area > 0) {
              const stW = maxX - minX + 1;
              const stH = maxY - minY + 1;
              const cMask = new Uint8Array(stW * stH);

              for (let y = 0; y < stH; y++) {
                for (let x = 0; x < stW; x++) {
                  if (labels[(minY + y) * W + (minX + x)] === count) {
                    cMask[y * stW + x] = 1;
                  }
                }
              }

              const rawPts = marchingSquaresContour(cMask, stW, stH);

              if (rawPts.length >= 3) {
                const mapped: [number, number][] = rawPts.map(([x, y]) => [x + minX, y + minY]);
                
                let startIdx = -1;
                for (let j = 0; j < mapped.length; j++) {
                  if (junctions.has(`${mapped[j][0]},${mapped[j][1]}`)) {
                    startIdx = j;
                    break;
                  }
                }

                let smoothedMapped: [number, number][] = [];

                if (startIdx === -1) {
                  smoothedMapped = smoothPathSmart(simplifyDP(mapped, 0.1), 4);
                } else {
                  const rotated = mapped.slice(startIdx).concat(mapped.slice(0, startIdx));
                  rotated.push(rotated[0]);

                  const subChains: [number, number][][] = [];
                  let currentSubChain: [number, number][] = [rotated[0]];

                  for (let j = 1; j < rotated.length; j++) {
                    currentSubChain.push(rotated[j]);
                    if (junctions.has(`${rotated[j][0]},${rotated[j][1]}`)) {
                      subChains.push(currentSubChain);
                      currentSubChain = [rotated[j]];
                    }
                  }

                  for (const sc of subChains) {
                    const smoothedSc = smoothPathSmart(simplifyDP(sc, 0.1), 4);
                    for (let j = 0; j < smoothedSc.length - 1; j++) {
                      smoothedMapped.push(smoothedSc[j]);
                    }
                  }
                }
                
                const { dist: distMap, maxDist, maxLoc } = distTransform(cMask, stW, stH);

                const labelPositions = generateLabelPositions(distMap, stW, stH, minX, minY, maxDist, area);

                contours.push({
                  points: smoothedMapped,
                  smoothPoints: smoothedMapped,
                  labelId: ci,
                  center: [maxLoc[0] + minX, maxLoc[1] + minY],
                  maxDist,
                  area: area,
                  labelPositions,
                });
              }
            }
            count++;
          }
        }
      };

      for (let ci = 0; ci < K; ci++) {
        extractContoursForColor(ci);
        postProgress(`Трассировка… ${ci + 1}/${K}`, 60 + Math.round((ci / K) * 28));
      }

      contours.sort((a, b) => b.area - a.area);
      resolveAllLabelCollisions(contours, W, H, final);

      postProgress("Построение превью…", 90);
      const prev = new Uint8ClampedArray(N * 4);
      for (let i = 0; i < N; i++) {
        const c = final[i] < K ? palette[final[i]] : [255, 255, 255];
        prev[i * 4] = c[0];
        prev[i * 4 + 1] = c[1];
        prev[i * 4 + 2] = c[2];
        prev[i * 4 + 3] = 255;
      }

      const pal: Record<number, [number, number, number]> = {};
      for (let i = 0; i < K; i++) pal[i] = palette[i];

      postProgress("Готово!", 100);

      const boundaryEdgesBuffer = new Float32Array(boundaryEdges.flat()).buffer;

      (self as any).postMessage(
        {
          type: "result",
          data: {
            previewBuffer: prev.buffer,
            imgW: W,
            imgH: H,
            contoursData: contours,
            colorPalette: pal,
            validLabels: Array.from(valid),
            scaleFactor: 1,
            autoColors: K,
            autoDetail: detail,
            labelMaskBuffer: final.buffer,
            boundaryEdgesBuffer,
          },
        },
        [prev.buffer, final.buffer, boundaryEdgesBuffer]
      );
    } catch (error: any) {
      self.postMessage({ type: "error", error: error.message });
    }
  }

  // 2. ГЕНЕРАЦИЯ SVG В ФОНЕ
  if (type === "export_svg") {
    const {
      res, contourWeight, numberWeight, colored, activeArray, showNums,
      isArtisticMode, artisticStep, artisticPresetId,
      notanLevels = 2,
      notanThreshold = 128,
      artIntensity = 100,
      customArtPalette,
    } = e.data.payload;

    const { imgW, imgH, contoursData, colorPalette, boundaryEdges } = res;
    const active = new Set(activeArray);
    const sorted = [...contoursData].sort((a: any, b: any) => b.area - a.area);

    const activePalette: Record<number, [number, number, number]> = {};
    const preset = artisticPresetId || 'original';

    for (const [key, rgb] of Object.entries(colorPalette)) {
      const id = Number(key);
      const rgbArr = rgb as [number, number, number];
      if (isArtisticMode) {
        activePalette[id] = computeArtisticColor(
          rgbArr, artisticStep, preset,
          notanLevels, notanThreshold, artIntensity,
          customArtPalette,
        );
      } else {
        activePalette[id] = rgbArr;
      }
    }

    let fills = "";
    const shouldFill = isArtisticMode ? artisticStep > 0 && artisticStep < 3 : colored;

    if (shouldFill) {
      for (const cd of sorted) {
        const smoothed = cd.points;
        
        if (smoothed && smoothed.length > 0) {
          const act = isArtisticMode || active.has(cd.labelId);
          const col = activePalette[cd.labelId];
          
          let d = `M ${smoothed[0][0].toFixed(1)} ${smoothed[0][1].toFixed(1)} `;
          for (let i = 1; i < smoothed.length; i++) {
             d += `L ${smoothed[i][0].toFixed(1)} ${smoothed[i][1].toFixed(1)} `;
          }
          d += "Z";

          fills += act && col
            ? `<path d="${d}" fill="rgb(${col[0]},${col[1]},${col[2]})" stroke="rgb(${col[0]},${col[1]},${col[2]})" stroke-width="0.6" stroke-linejoin="round"/>`
            : `<path d="${d}" fill="white" stroke="white" stroke-width="0.6" stroke-linejoin="round"/>`;
        }
      }
    }

    let lines = "";
    const shouldDrawLines = isArtisticMode ? artisticStep === 0 || artisticStep === 3 : true;

    if (shouldDrawLines) {
      const cleanEdges = boundaryEdges.filter(
        (edge: [number, number, number, number]) =>
          !(edge[1] === 0 && edge[3] === 0) &&
          !(edge[1] === imgH && edge[3] === imgH) &&
          !(edge[0] === 0 && edge[2] === 0) &&
          !(edge[0] === imgW && edge[2] === imgW)
      );

      const chains = buildSmoothChains(cleanEdges, 0.1, 4);

      const getBezierPath = (pts: [number, number][]) => {
        if (pts.length < 2) return "";
        for (let i = 0; i < pts.length - 1; i++) {
          const dx = pts[i+1][0] - pts[i][0];
          const dy = pts[i+1][1] - pts[i][1];
          if (dx * dx + dy * dy > 40000) return "";
        }
        let d = `M ${pts[0][0].toFixed(1)} ${pts[0][1].toFixed(1)}`;
        if (pts.length === 2) {
          d += ` L ${pts[1][0].toFixed(1)} ${pts[1][1].toFixed(1)}`;
          return d;
        }
        const n = pts.length;
        const t = 0.15;
        for (let i = 0; i < n - 1; i++) {
          const p0 = pts[i === 0 ? 0 : i - 1];
          const p1 = pts[i];
          const p2 = pts[i + 1];
          const p3 = pts[i + 2 >= n ? n - 1 : i + 2];
          const cp1x = p1[0] + (p2[0] - p0[0]) * t;
          const cp1y = p1[1] + (p2[1] - p0[1]) * t;
          const cp2x = p2[0] - (p3[0] - p1[0]) * t;
          const cp2y = p2[1] - (p3[1] - p1[1]) * t;
          d += ` C ${cp1x.toFixed(1)} ${cp1y.toFixed(1)}, ${cp2x.toFixed(1)} ${cp2y.toFixed(1)}, ${p2[0].toFixed(1)} ${p2[1].toFixed(1)}`;
        }
        return d;
      };

      if (isArtisticMode && artisticStep === 3 && contourWeight > 0) {
        const weightFactor = contourWeight / 50;
        const svgPaths = chains.map((ch) => {
          const d = getBezierPath(ch);
          if (!d) return "";
          const shadow = `<path d="${d}" fill="none" stroke="rgba(0,0,0,0.4)" stroke-width="${(2.5 * weightFactor).toFixed(2)}" stroke-linecap="round" stroke-linejoin="round"/>`;
          const highlight = `<path d="${d}" fill="none" stroke="rgba(255,255,255,0.8)" stroke-width="${(1.0 * weightFactor).toFixed(2)}" stroke-linecap="round" stroke-linejoin="round"/>`;
          return shadow + highlight;
        }).join("");
        lines = svgPaths;
      } else {
        const lineAlpha = contourWeight === 0 ? 0 : (isArtisticMode ? 0.6 : 0.2 + (contourWeight / 100) * 0.8);
        const lineWidth = contourWeight === 0 ? 0 : (isArtisticMode ? 1.0 : 0.5 + (contourWeight / 100) * 1.5);
        if (lineWidth > 0) {
          const strokeColor = `rgba(40,40,40,${lineAlpha.toFixed(2)})`;
          const svgPaths = chains.map((ch) => {
            const d = getBezierPath(ch);
            if (!d) return "";
            return `<path d="${d}" fill="none" stroke="${strokeColor}" stroke-width="${lineWidth.toFixed(2)}" stroke-linecap="round" stroke-linejoin="round"/>`;
          }).join("");
          lines = svgPaths;
        }
      }
    }

    let texts = "";
    if (showNums && !isArtisticMode) {
      const numAlpha = (numberWeight === 0 ? 0 : 0.15 + (numberWeight / 100) * 0.85).toFixed(2);
      for (const cd of sorted) {
        for (const lbl of cd.labelPositions) {
          if (lbl.maxDist < 2.5) continue;
          const fs = Math.max(5, Math.min(12, lbl.maxDist * 1.2));
          const act = colored && active.has(cd.labelId);
          const col = colorPalette[cd.labelId];
          let tf = `rgba(51,51,51,${numAlpha})`;

          if (act && col) {
            const lum = 0.299 * col[0] + 0.587 * col[1] + 0.114 * col[2];
            tf = lum > 140 ? `rgba(0,0,0,${numAlpha})` : `rgba(255,255,255,${numAlpha})`;
          }

          const labelText = escapeXml(String(cd.labelId + 1));
          texts += `<text x="${lbl.x.toFixed(1)}" y="${lbl.y.toFixed(1)}" font-size="${fs.toFixed(1)}" text-anchor="middle" dominant-baseline="central" font-family="sans-serif" font-weight="bold" fill="${tf}">${labelText}</text>`;
        }
      }
    }

    const svgString = generateSvgTemplate({
      imgW,
      imgH,
      isTransparent: isArtisticMode && artisticStep === 3,
      fills,
      lines,
      texts
    });

    self.postMessage({ type: "export_result", data: svgString });
  }

  // 3. ГЕНЕРАЦИЯ HTML В ФОНЕ
  if (type === "export_html") {
    const {
      res, contourWeight, isArtisticMode, origBase64,
      artisticPresetId,
      notanLevels = 2,
      notanThreshold = 128,
      artIntensity = 100,
      customArtPalette,
    } = e.data.payload;

    const { imgW, imgH, colorPalette, validLabels, contoursData, boundaryEdges, labelMask } = res;

    const sl = [...validLabels].sort((a: number, b: number) => a - b);
    const palJSON: Record<number, [number, number, number]> = {};
    for (const lid of sl) {
      const c = colorPalette[lid];
      if (c) palJSON[lid] = c;
    }

    const maskRLE = rleEncode(labelMask);

    const cleanEdges = boundaryEdges.filter(
      (edge: [number, number, number, number]) =>
        !(edge[1] === 0 && edge[3] === 0) &&
        !(edge[1] === imgH && edge[3] === imgH) &&
        !(edge[0] === 0 && edge[2] === 0) &&
        !(edge[0] === imgW && edge[2] === imgW)
    );

    const chains = buildSmoothChains(cleanEdges);
    const chainsJSON = JSON.stringify(
      chains.map((ch) => simplifyDP(ch, 0.1).map(([x, y]) => [Math.round(x * 10) / 10, Math.round(y * 10) / 10]))
    );

    const labelsJSON = JSON.stringify(
      contoursData.map((cd: any) => ({
        id: cd.labelId,
        a: cd.area,
        poly: cd.points.map(([x, y]: any) => [Math.round(x * 10) / 10, Math.round(y * 10) / 10]),
        lp: cd.labelPositions
          .filter((lp: any) => lp.maxDist >= 2.5)
          .map((lp: any) => ({
            x: Math.round(lp.x * 10) / 10,
            y: Math.round(lp.y * 10) / 10,
            d: Math.round(lp.maxDist * 10) / 10,
          })),
      }))
    );

    const lineAlpha = String(contourWeight === 0 ? "0" : (0.2 + (contourWeight / 100) * 0.8).toFixed(2));
    const lineWidth = String(contourWeight === 0 ? "0" : (0.5 + (contourWeight / 100) * 1.5).toFixed(2));

    let htmlString = "";

    if (isArtisticMode) {
      const customPalJS = customArtPalette && customArtPalette.length >= 2
        ? JSON.stringify(customArtPalette)
        : 'null';

      htmlString = generateArtisticHtmlTemplate({
        imgW, imgH,
        palJSON, chainsJSON, maskRLE,
        notanLevels, notanThreshold, artIntensity,
        preset: artisticPresetId || 'original',
        customPalJS, origBase64
      });
    } else {
      const palButtons = sl
        .map((lid: number) => {
          const c = colorPalette[lid];
          if (!c) return "";
          const lum = 0.299 * c[0] + 0.587 * c[1] + 0.114 * c[2];
          const tc = lum > 140 ? "#000" : "#fff";
          return `<div id="p${lid}" class="cb" onclick="tc(${lid})" style="background:rgb(${c[0]},${c[1]},${c[2]});color:${tc}" title="Цвет ${lid + 1}"><span>${lid + 1}</span></div>`;        })
        .join("");

      htmlString = generatePbnHtmlTemplate({
        imgW, imgH,
        palJSON, chainsJSON, labelsJSON, maskRLE, sl,
        lineAlpha, lineWidth, palButtons
      });
    }

    self.postMessage({ type: "export_result", data: htmlString });
  }
};