// src/generator/utils/worker/quantization.ts
import { rgbToLab, labToRgb, deltaE00, rgbToHsl, hslToRgb } from '../../../utils/colorMath';

export interface ColorBox {
  colors: Uint8Array;
  count: number;
  rMin: number; rMax: number;
  gMin: number; gMax: number;
  bMin: number; bMax: number;
}

/**
 * Основная функция генерации палитры.
 * Использует адаптивное сэмплирование и взвешенный K-Means.
 */
export function medianCut(data: Uint8ClampedArray, w: number, h: number, numColors: number): [number, number, number][] {
  const total = w * h;
  const sampled: number[] = [];
  
  // 1. Адаптивное сэмплирование: берем больше образцов из детализированных и ярких областей
  const step = Math.max(1, Math.floor(total / 100000));
  for (let i = 0; i < total; i += step) {
    const p = i * 4;
    const r = data[p], g = data[p + 1], b = data[p + 2];
    
    // Считаем локальную "важность" (насыщенность + градиент)
    const mx = Math.max(r, g, b), mn = Math.min(r, g, b);
    const saturation = mx > 0 ? (mx - mn) / mx : 0;
    
    // Добавляем пиксель. Если он яркий/насыщенный, добавляем его несколько раз (вес)
    const weight = 1 + Math.floor(saturation * 3);
    for (let k = 0; k < weight; k++) {
      sampled.push(r, g, b);
    }
  }

  const allSamples = new Uint8Array(sampled);

  const makeBox = (colors: Uint8Array): ColorBox => {
    let rMin = 255, rMax = 0, gMin = 255, gMax = 0, bMin = 255, bMax = 0;
    for (let i = 0; i < colors.length; i += 3) {
      const r = colors[i], g = colors[i + 1], b = colors[i + 2];
      if (r < rMin) rMin = r; if (r > rMax) rMax = r;
      if (g < gMin) gMin = g; if (g > gMax) gMax = g;
      if (b < bMin) bMin = b; if (b > bMax) bMax = b;
    }
    return { colors, count: colors.length / 3, rMin, rMax, gMin, gMax, bMin, bMax };
  };

  // 2. Начальное разбиение пространства
  let boxes: ColorBox[] = [makeBox(allSamples)];
  const targetBoxes = Math.min(numColors * 2.5, 300);

  while (boxes.length < targetBoxes) {
    let bestIdx = 0, bestScore = -1;
    for (let i = 0; i < boxes.length; i++) {
      const b = boxes[i];
      if (b.count < 2) continue;
      // Оценка важности бокса: объем в пространстве * количество пикселей
      const score = Math.max(b.rMax - b.rMin, b.gMax - b.gMin, b.bMax - b.bMin) * Math.log2(b.count + 1);
      if (score > bestScore) { bestScore = score; bestIdx = i; }
    }
    if (bestScore <= 0) break;

    const box = boxes[bestIdx];
    const axis = (box.rMax - box.rMin >= box.gMax - box.gMin && box.rMax - box.rMin >= box.bMax - box.bMin) ? 0 :
                 (box.gMax - box.gMin >= box.bMax - box.bMin) ? 1 : 2;

    const triples: number[][] = [];
    for (let i = 0; i < box.colors.length; i += 3) {
      triples.push([box.colors[i], box.colors[i + 1], box.colors[i + 2]]);
    }
    triples.sort((a, b) => a[axis] - b[axis]);
    
    const mid = Math.floor(triples.length / 2);
    const left = new Uint8Array(mid * 3);
    const right = new Uint8Array((triples.length - mid) * 3);

    for (let i = 0; i < mid; i++) {
      left[i*3]=triples[i][0]; left[i*3+1]=triples[i][1]; left[i*3+2]=triples[i][2];
    }
    for (let i = mid; i < triples.length; i++) {
      const j = i - mid;
      right[j*3]=triples[i][0]; right[j*3+1]=triples[i][1]; right[j*3+2]=triples[i][2];
    }
    boxes.splice(bestIdx, 1, makeBox(left), makeBox(right));
  }

  const candidates = boxes.map(b => {
    let r = 0, g = 0, b_ = 0;
    for (let i = 0; i < b.colors.length; i += 3) {
      r += b.colors[i]; g += b.colors[i + 1]; b_ += b.colors[i + 2];
    }
    return [Math.round(r/b.count), Math.round(g/b.count), Math.round(b_/b.count)] as [number, number, number];
  });

  // 3. Уточнение палитры (Взвешенный K-Means)
  return refinePalette(candidates, data, w, h, numColors);
}

export function refinePalette(candidates: [number, number, number][], data: Uint8ClampedArray, w: number, h: number, K: number): [number, number, number][] {
  const total = w * h;
  const step = Math.max(1, Math.floor(total / 40000));

  // Инициализация центров (выбираем максимально разнесенные цвета из кандидатов)
  let centers: [number, number, number][] = [candidates[0]];
  let cLab = [rgbToLab(candidates[0])];
  
  while (centers.length < K && centers.length < candidates.length) {
    let maxDist = -1, bestIdx = 0;
    for (let i = 0; i < candidates.length; i++) {
      const lab = rgbToLab(candidates[i]);
      let minDist = Infinity;
      for (const cl of cLab) {
        const d = (lab[0]-cl[0])**2 + (lab[1]-cl[1])**2 + (lab[2]-cl[2])**2;
        if (d < minDist) minDist = d;
      }
      if (minDist > maxDist) { maxDist = minDist; bestIdx = i; }
    }
    centers.push(candidates[bestIdx]);
    cLab.push(rgbToLab(candidates[bestIdx]));
  }

  // Итерации K-Means
  for (let iter = 0; iter < 4; iter++) {
    const sumL = new Float64Array(K), sumA = new Float64Array(K), sumB = new Float64Array(K), counts = new Float64Array(K);

    for (let i = 0; i < total; i += step) {
      const p = i * 4;
      const r = data[p], g = data[p + 1], b = data[p + 2];
      const lab = rgbToLab([r, g, b]);
      
      let bd = Infinity, bk = 0;
      for (let c = 0; c < centers.length; c++) {
        const d = (lab[0]-cLab[c][0])**2 + (lab[1]-cLab[c][1])**2 + (lab[2]-cLab[c][2])**2;
        if (d < bd) { bd = d; bk = c; }
      }

      // Вес пикселя: насыщенные пиксели важнее (предотвращает серые пятна)
      const mx = Math.max(r, g, b), mn = Math.min(r, g, b);
      const weight = 1.0 + (mx > 0 ? (mx - mn) / mx : 0) * 3.0;

      sumL[bk] += lab[0] * weight;
      sumA[bk] += lab[1] * weight;
      sumB[bk] += lab[2] * weight;
      counts[bk] += weight;
    }

    for (let c = 0; c < centers.length; c++) {
      if (counts[c] > 0) {
        cLab[c] = [sumL[c] / counts[c], sumA[c] / counts[c], sumB[c] / counts[c]];
        centers[c] = labToRgb(cLab[c][0], cLab[c][1], cLab[c][2]) as [number, number, number];
      }
    }
  }

  // 4. Умное слияние близких цветов
  const finalPalette: [number, number, number][] = [];
  const merged = new Set<number>();

  for (let i = 0; i < centers.length; i++) {
    if (merged.has(i)) continue;
    
    for (let j = i + 1; j < centers.length; j++) {
      if (merged.has(j)) continue;
      const dE = deltaE00(cLab[i], cLab[j]);
      
      // Порог слияния зависит от насыщенности: яркие цвета бережем сильнее
      const [h, s, l] = rgbToHsl(centers[i]);
      const mergeThreshold = s > 0.4 ? 2.5 : 4.5;
      
      if (dE < mergeThreshold) merged.add(j);
    }
    finalPalette.push(centers[i]);
  }

  // Финальная коррекция: легкое усиление контраста и насыщенности для "художественного" эффекта
  return finalPalette.map(rgb => {
    const [h, s, l] = rgbToHsl(rgb);
    if (s < 0.05) return rgb; // Не трогаем нейтральные цвета
    
    const newS = Math.min(1.0, s * 1.08); // +8% к насыщенности
    const newL = l < 0.5 ? l * 0.96 : Math.min(1.0, l * 1.02); // Усиливаем контраст
    return hslToRgb(h, newS, newL) as [number, number, number];
  });
}
