// src/generator/utils/worker/filters.ts
import { deltaE00 } from '../../../utils/colorMath';

/**
 * Билатеральный фильтр для сглаживания изображения с сохранением краев.
 */
export function bilateralFilter(data: Uint8ClampedArray, w: number, h: number, radius: number): Uint8ClampedArray {
  if (radius <= 0) return data;
  const out = new Uint8ClampedArray(data.length);
  const sigmaS = radius, sigmaC = 30.0;

  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const idx = (y * w + x) * 4;
      const cr = data[idx], cg = data[idx + 1], cb = data[idx + 2];
      let weightSum = 0, rSum = 0, gSum = 0, bSum = 0;

      const yMin = Math.max(0, y - radius), yMax = Math.min(h - 1, y + radius);
      const xMin = Math.max(0, x - radius), xMax = Math.min(w - 1, x + radius);

      for (let ny = yMin; ny <= yMax; ny++) {
        for (let nx = xMin; nx <= xMax; nx++) {
          const nIdx = (ny * w + nx) * 4;
          const nr = data[nIdx], ng = data[nIdx + 1], nb = data[nIdx + 2];

          const dS = (nx - x) * (nx - x) + (ny - y) * (ny - y);
          const dC = (nr - cr) * (nr - cr) + (ng - cg) * (ng - cg) + (nb - cb) * (nb - cb);

          const weight = Math.exp(-(dS / (2 * sigmaS * sigmaS)) - (dC / (2 * sigmaC * sigmaC)));

          weightSum += weight; rSum += nr * weight; gSum += ng * weight; bSum += nb * weight;
        }
      }

      out[idx] = Math.round(rSum / weightSum);
      out[idx + 1] = Math.round(gSum / weightSum);
      out[idx + 2] = Math.round(bSum / weightSum);
      out[idx + 3] = 255;
    }
  }
  return out;
}

/**
 * Умная очистка мелких зон (островов).
 */
export function fastRegionCleanup(
  mask: Uint8Array,
  w: number,
  h: number,
  minArea: number,
  palLab?: [number, number, number][]
): Uint8Array {
  if (minArea <= 1) return mask;
  const n = w * h;
  const labels = new Int32Array(n);
  const q = new Int32Array(n);
  
  for (let iter = 0; iter < 2; iter++) {
    labels.fill(-1);
    const regions: { area: number; color: number; label: number }[] = [];
    let nextLabel = 0;

    for (let i = 0; i < n; i++) {
      if (labels[i] === -1) {
        const color = mask[i];
        let head = 0, tail = 0;
        q[tail++] = i;
        labels[i] = nextLabel;
        let area = 0;

        while (head < tail) {
          const curr = q[head++];
          area++;
          const cx = curr % w, cy = (curr / w) | 0;

          if (cx > 0 && labels[curr - 1] === -1 && mask[curr - 1] === color) { labels[curr - 1] = nextLabel; q[tail++] = curr - 1; }
          if (cx < w - 1 && labels[curr + 1] === -1 && mask[curr + 1] === color) { labels[curr + 1] = nextLabel; q[tail++] = curr + 1; }
          if (cy > 0 && labels[curr - w] === -1 && mask[curr - w] === color) { labels[curr - w] = nextLabel; q[tail++] = curr - w; }
          if (cy < h - 1 && labels[curr + w] === -1 && mask[curr + w] === color) { labels[curr + w] = nextLabel; q[tail++] = curr + w; }
        }
        regions.push({ area, color, label: nextLabel });
        nextLabel++;
      }
    }

    const smallRegions = regions.filter(r => r.area < minArea);
    if (smallRegions.length === 0) break;

    const neighborCounts = new Map<number, Map<number, number>>(); 
    for (const r of smallRegions) {
      neighborCounts.set(r.label, new Map());
    }

    for (let i = 0; i < n; i++) {
      const l = labels[i];
      if (neighborCounts.has(l)) {
        const cx = i % w, cy = (i / w) | 0;
        const counts = neighborCounts.get(l)!;
        const check = (ni: number) => {
          const nl = labels[ni];
          if (nl !== l) {
            const nc = mask[ni];
            counts.set(nc, (counts.get(nc) || 0) + 1);
          }
        };
        if (cx > 0) check(i - 1);
        if (cx < w - 1) check(i + 1);
        if (cy > 0) check(i - w);
        if (cy < h - 1) check(i + w);
      }
    }

    let changed = false;
    const mergeMap = new Map<number, number>(); 
    for (const r of smallRegions) {
      const counts = neighborCounts.get(r.label)!;
      if (counts.size === 0) continue;
      let bestColor = r.color, maxScore = -1;
      for (const [nc, count] of counts.entries()) {
        let score = count;
        if (palLab) {
          const dE = deltaE00(palLab[r.color], palLab[nc]);
          score = count * (100 / (dE + 5.0));
        }
        if (score > maxScore) { maxScore = score; bestColor = nc; }
      }
      if (bestColor !== r.color) { mergeMap.set(r.label, bestColor); changed = true; }
    }
    if (!changed) break;
    for (let i = 0; i < n; i++) {
      const l = labels[i];
      if (mergeMap.has(l)) mask[i] = mergeMap.get(l)!;
    }
  }
  return mask;
}

/**
 * Фильтр расширения узких зон.
 */
export function thickeningFilter(mask: Uint8Array, w: number, h: number, minThickness: number): Uint8Array {
  if (minThickness <= 1.2) return mask;
  const n = w * h;
  const out = new Uint8Array(mask);
  const dist = new Float32Array(n).fill(100);
  const q = new Int32Array(n);
  let head = 0, tail = 0;

  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = y * w + x;
      let isB = false;
      if (x > 0 && mask[i-1] !== mask[i]) isB = true;
      else if (x < w - 1 && mask[i+1] !== mask[i]) isB = true;
      else if (y > 0 && mask[i-w] !== mask[i]) isB = true;
      else if (y < h - 1 && mask[i+w] !== mask[i]) isB = true;
      if (isB) { dist[i] = 0; q[tail++] = i; }
    }
  }

  while (head < tail) {
    const i = q[head++];
    const x = i % w, y = (i / w) | 0;
    const d = dist[i];
    for (let dy = -1; dy <= 1; dy++) {
      for (let dx = -1; dx <= 1; dx++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx, ny = y + dy;
        if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
          const ni = ny * w + nx;
          const nd = d + (dx === 0 || dy === 0 ? 1 : 1.4);
          if (dist[ni] > nd) { dist[ni] = nd; q[tail++] = ni; }
        }
      }
    }
  }

  const threshold = minThickness / 2.0;
  const toThicken = new Uint8Array(n);
  for (let i = 0; i < n; i++) { if (dist[i] > 0 && dist[i] < threshold) toThicken[i] = 1; }

  // Расширяем итеративно
  for (let iter = 0; iter < 2; iter++) {
    const temp = new Uint8Array(out);
    for (let i = 0; i < n; i++) {
      if (toThicken[i]) {
        const c = out[i];
        const x = i % w, y = (i / w) | 0;
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
            const ni = (y + dy) * w + (x + dx);
            if (ni >= 0 && ni < n && dist[ni] <= 0.1 && out[ni] !== c) {
              // Если мы на границе другого цвета, и этот сосед не "узкий", заменяем его
              const oppIdx = ni + (ni - i);
              if (oppIdx >= 0 && oppIdx < n && !toThicken[oppIdx]) { temp[ni] = c; }
            }
          }
        }
      }
    }
    out.set(temp);
  }
  return out;
}

/**
 * Модальный фильтр.
 */
export function modeFilter(mask: Uint8Array, w: number, h: number, nC: number): Uint8Array {
  const out = new Uint8Array(mask.length);
  const histLen = Math.max(nC + 2, 256);
  const hist = new Uint16Array(histLen);

  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      hist.fill(0);
      for (let dy = -1; dy <= 1; dy++) {
        const ny = y + dy;
        if (ny < 0 || ny >= h) continue;
        for (let dx = -1; dx <= 1; dx++) {
          const nx = x + dx;
          if (nx < 0 || nx >= w) continue;
          hist[mask[ny * w + nx]]++;
        }
      }
      let bv = mask[y * w + x], bc = 0;
      for (let i = 0; i < histLen; i++) { if (hist[i] > bc) { bc = hist[i]; bv = i; } }
      out[y * w + x] = bv;
    }
  }
  return out;
}
