// src/generator/utils/worker/labels.ts

/**
 * Преобразование расстояний (8-связное) для поиска центра зоны.
 */
export function distTransform(mask: Uint8Array, w: number, h: number): { dist: Float32Array; maxDist: number; maxLoc: [number, number] } {
  const n = w * h;
  const dist = new Float32Array(n).fill(-1);
  const q = new Int32Array(n);
  let head = 0, tail = 0;

  // Инициализация границ
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = y * w + x;
      if (!mask[i]) continue;
      
      let isBoundary = x === 0 || y === 0 || x === w - 1 || y === h - 1;
      if (!isBoundary) {
        // Проверяем 8 соседей
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
            if (dx === 0 && dy === 0) continue;
            if (!mask[(y + dy) * w + (x + dx)]) {
              isBoundary = true;
              break;
            }
          }
          if (isBoundary) break;
        }
      }
      
      if (isBoundary) {
        dist[i] = 0;
        q[tail++] = i;
      }
    }
  }

  // BFS для заполнения расстояний
  while (head < tail) {
    const i = q[head++];
    const x = i % w, y = (i / w) | 0;
    const d = dist[i];

    for (let dy = -1; dy <= 1; dy++) {
      for (let dx = -1; dx <= 1; dx++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx, ny = y + dy;
        if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
          const ni = ny * w + nx;
          if (mask[ni] && dist[ni] < 0) {
            // Вес диагонали 1.4, прямой линии 1.0
            const weight = (dx !== 0 && dy !== 0) ? 1.414 : 1.0;
            dist[ni] = d + weight;
            q[tail++] = ni;
          }
        }
      }
    }
  }

  let md = 0, ml: [number, number] = [0, 0];
  for (let i = 0; i < n; i++) {
    if (dist[i] > md) {
      md = dist[i];
      ml = [i % w, (i / w) | 0];
    }
  }
  return { dist, maxDist: md, maxLoc: ml };
}

/**
 * Генерация позиций для номеров зон.
 */
export function generateLabelPositions(dist: Float32Array, w: number, h: number, ox: number, oy: number, maxDist: number, area: number): any[] {
  const positions: any[] = [];
  if (maxDist < 2.0) return positions;

  // Для маленьких зон ставим только одну метку в самом глубоком месте
  if (area < 1500 || maxDist < 10) {
    let bd = 0, bx = 0, by = 0;
    for (let i = 0; i < dist.length; i++) {
      if (dist[i] > bd) {
        bd = dist[i];
        bx = i % w;
        by = (i / w) | 0;
      }
    }
    positions.push({ x: bx + ox, y: by + oy, maxDist: bd });
    return positions;
  }

  // Для больших зон используем адаптивную сетку для поиска нескольких меток
  const spacing = Math.max(50, maxDist * 3.5);
  const minDistForLabel = Math.max(4, maxDist * 0.4);
  const candidates: { x: number; y: number; d: number }[] = [];
  
  // Шаг сетки зависит от размера зоны
  const step = Math.max(2, Math.floor(spacing / 4));

  for (let y = 0; y < h; y += step) {
    for (let x = 0; x < w; x += step) {
      const d = dist[y * w + x];
      if (d < minDistForLabel) continue;

      // Проверяем, является ли точка локальным максимумом в своем радиусе
      let isLocalMax = true;
      const r = Math.ceil(step * 1.5);
      for (let dy = -r; dy <= r && isLocalMax; dy += step) {
        for (let dx = -r; dx <= r; dx += step) {
          if (dx === 0 && dy === 0) continue;
          const nx = x + dx, ny = y + dy;
          if (nx >= 0 && nx < w && ny >= 0 && ny < h) {
            if (dist[ny * w + nx] > d + 0.1) {
              isLocalMax = false;
              break;
            }
          }
        }
      }
      if (isLocalMax) {
        candidates.push({ x, y, d });
      }
    }
  }

  // Сортируем кандидатов по "глубине"
  candidates.sort((a, b) => b.d - a.d);

  // Выбираем метки, соблюдая минимальное расстояние между ними
  for (const cand of candidates) {
    let tooClose = false;
    for (const p of positions) {
      const dx = cand.x + ox - p.x;
      const dy = cand.y + oy - p.y;
      if (dx * dx + dy * dy < spacing * spacing) {
        tooClose = true;
        break;
      }
    }
    if (!tooClose) {
      positions.push({ x: cand.x + ox, y: cand.y + oy, maxDist: cand.d });
    }
  }

  // Гарантируем хотя бы одну метку, если кандидаты не прошли проверку
  if (positions.length === 0) {
    let bd = 0, bx = 0, by = 0;
    for (let i = 0; i < dist.length; i++) {
      if (dist[i] > bd) { bd = dist[i]; bx = i % w; by = (i / w) | 0; }
    }
    positions.push({ x: bx + ox, y: by + oy, maxDist: bd });
  }

  return positions;
}

/**
 * Разрешение коллизий между номерами всех зон.
 */
export function resolveAllLabelCollisions(contours: any[], w: number, h: number, mask: Uint8Array): void {
  const placed: { x: number; y: number; r: number; id: number }[] = [];

  // Собираем все метки в один плоский список для обработки
  const allLabels: any[] = [];
  for (const cd of contours) {
    for (const lbl of cd.labelPositions) {
      if (lbl.maxDist < 2) continue;
      allLabels.push({
        lbl,
        id: cd.labelId,
        area: cd.area
      });
    }
  }

  // Сортируем: сначала метки для маленьких зон (они важнее, так как их сложнее разместить)
  allLabels.sort((a, b) => a.area - b.area);

  for (const item of allLabels) {
    const { lbl } = item;
    const fs = Math.max(6, Math.min(14, lbl.maxDist * 1.2));
    const textR = fs * 0.7; // Радиус зоны безопасности вокруг текста

    let cx = lbl.x, cy = lbl.y;

    // Итеративное расталкивание (до 10 попыток)
    for (let att = 0; att < 10; att++) {
      let collided = false;
      let nextCx = cx;
      let nextCy = cy;

      for (const p of placed) {
        const dx = nextCx - p.x;
        const dy = nextCy - p.y;
        const minDist = textR + p.r + 2; // +2 пикселя зазора
        
        if (dx * dx + dy * dy < minDist * minDist) {
          const dist = Math.sqrt(dx * dx + dy * dy) || 1;
          const force = (minDist - dist) / dist;
          
          // Сдвигаем метку в сторону от препятствия
          nextCx += dx * force * 0.6;
          nextCy += dy * force * 0.6;
          collided = true;
        }
      }

      if (collided) {
        // Проверяем, не вылетела ли метка за пределы своей зоны
        const ix = Math.floor(nextCx);
        const iy = Math.floor(nextCy);
        if (ix >= 0 && ix < w && iy >= 0 && iy < h && mask[iy * w + ix] === item.id) {
          cx = nextCx;
          cy = nextCy;
        } else {
          // Если метка вылетает из своей зоны, отменяем сдвиг и прекращаем расталкивание для этой метки
          break;
        }
      } else {
        break;
      }
    }

    lbl.x = cx;
    lbl.y = cy;
    placed.push({ x: cx, y: cy, r: textR, id: item.id });
  }
}
