// src/generator/utils/worker/contours.ts

export function extractBoundaryEdges(mask: Uint8Array, w: number, h: number): [number, number, number, number][] {
  const edges: [number, number, number, number][] = [];
  for (let y = 1; y < h; y++) {
    let x = 0;
    while (x < w) {
      const c1 = mask[y * w + x];
      const c2 = mask[(y - 1) * w + x];
      if (c1 !== c2) {
        const xs = x;
        x++;
        while (x < w && mask[y * w + x] === c1 && mask[(y - 1) * w + x] === c2) x++;
        edges.push([xs, y, x, y]);
      } else {
        x++;
      }
    }
  }
  for (let x = 1; x < w; x++) {
    let y = 0;
    while (y < h) {
      const c1 = mask[y * w + x];
      const c2 = mask[y * w + x - 1];
      if (c1 !== c2) {
        const ys = y;
        y++;
        while (y < h && mask[y * w + x] === c1 && mask[y * w + x - 1] === c2) y++;
        edges.push([x, ys, x, y]);
      } else {
        y++;
      }
    }
  }
  // Верхняя граница (y = 0)
  let bx = 0;
  while (bx < w) {
    const c1 = mask[bx];
    const xs = bx;
    bx++;
    while (bx < w && mask[bx] === c1) bx++;
    edges.push([xs, 0, bx, 0]);
  }
  // Нижняя граница (y = h)
  bx = 0;
  while (bx < w) {
    const c1 = mask[(h - 1) * w + bx];
    const xs = bx;
    bx++;
    while (bx < w && mask[(h - 1) * w + bx] === c1) bx++;
    edges.push([xs, h, bx, h]);
  }
  // Левая граница (x = 0)
  let by = 0;
  while (by < h) {
    const c1 = mask[by * w];
    const ys = by;
    by++;
    while (by < h && mask[by * w] === c1) by++;
    edges.push([0, ys, 0, by]);
  }
  // Правая граница (x = w)
  by = 0;
  while (by < h) {
    const c1 = mask[by * w + w - 1];
    const ys = by;
    by++;
    while (by < h && mask[by * w + w - 1] === c1) by++;
    edges.push([w, ys, w, by]);
  }
  return edges;
}

export function msConfig(mask: Uint8Array, w: number, h: number, x: number, y: number): number {
  const tl = x > 0 && y > 0 && mask[(y - 1) * w + (x - 1)] ? 1 : 0;
  const tr = x < w && y > 0 && mask[(y - 1) * w + x] ? 1 : 0;
  const bl = x > 0 && y < h && mask[y * w + (x - 1)] ? 1 : 0;
  const br = x < w && y < h && mask[y * w + x] ? 1 : 0;
  return (tl << 3) | (tr << 2) | (br << 1) | bl;
}

export function msDirection(cfg: number, prevDir: number): number {
  switch (cfg) {
    case 1: return 2;
    case 2: return 1;
    case 3: return 2;
    case 4: return 0;
    case 5: return prevDir === 1 ? 0 : 2;
    case 6: return 1;
    case 7: return 2;
    case 8: return 3;
    case 9: return 3;
    case 10: return prevDir === 2 ? 1 : 3;
    case 11: return 3;
    case 12: return 0;
    case 13: return 0;
    case 14: return 1;
    default: return -1;
  }
}

export function marchingSquaresContour(mask: Uint8Array, w: number, h: number): [number, number][] {
  const pts: [number, number][] = [];
  let startX = -1, startY = -1;
  outer: for (let y = 0; y <= h; y++) {
    for (let x = 0; x <= w; x++) {
      const cfg = msConfig(mask, w, h, x, y);
      if (cfg > 0 && cfg < 15) { startX = x; startY = y; break outer; }
    }
  }
  if (startX < 0) return [];

  let cx = startX, cy = startY, prevDir = 0;
  const maxIter = w * h * 4;
  for (let iter = 0; iter < maxIter; iter++) {
    if (iter > 0 && cx === startX && cy === startY) break;
    pts.push([cx, cy]);
    const cfg = msConfig(mask, w, h, cx, cy);
    const dir = msDirection(cfg, prevDir);
    if (dir < 0) break;
    switch (dir) { case 0: cx++; break; case 1: cy++; break; case 2: cx--; break; case 3: cy--; break; }
    prevDir = dir;
    if (cx < -1 || cx > w + 1 || cy < -1 || cy > h + 1) break;
  }
  return pts;
}